import { Field, Form, useFormik } from "formik";

const AdminResult = ()  =>
{
    const formik = useFormik({
        initialValues :{
                homeTeam: '', 
                awayTeam: '',
                seasonId: ''},
        onSubmit : values => {
          alert(JSON.stringify(values, null, 2));}
        }   
    );

    return(

        <div>           
            <Form onSubmit={formik.handleSubmit}>
                <Field type="text" name="homeTeam" value={formik.values.homeTeam} onChange={formik.handleChange}/>
                <Field type="text" name="awayTeam" value={formik.values.awayTeam} onChange={formik.handleChange}/>
                <Field type="text" name="season" value={formik.values.seasonId} onChange={formik.handleChange}/>
                <button type="submit">Submit</button>
            </Form>            
        </div>
    );
}

export default AdminResult;
